</head>
<body>
    <div id="desktop">
        <div id="taskbar">
            <button class="launcher" id="open-files">📁 Files</button>
            <button class="launcher" id="open-notepad">📝 Notepad</button>
        </div>

        <div id="files-window" class="window hidden">
            <div class="window-header">
                <div class="window-title">File Manager</div>
                <button class="win-close">×</button>
            </div>
            <div class="window-content">
                <button id="files-up">← Up</button>
                <div id="files-path">/</div>
                <div id="files-list"></div>
            </div>
        </div>

        <div id="notepad-window" class="window hidden">
            <div class="window-header">
                <div class="window-title">Notepad</div>
                <button class="win-close">×</button>
            </div>
            <div class="notepad-controls">
                <div id="tabs"></div>
                <button id="new-tab">+ New</button>
            </div>
            <textarea id="editor" placeholder="Start typing..."></textarea>
        </div>
    </div>

    <script>
        const filesystem = {
            '/': {
                type: 'folder',
                children: {
                    'bin': { type: 'folder', children: {} },
                    'etc': { type: 'folder', children: {} },
                    'home': {
                        type: 'folder',
                        children: {
                            'user': {
                                type: 'folder',
                                children: {
                                    'Documents': { type: 'folder', children: {} },
                                    'Downloads': { type: 'folder', children: {} },
                                    'Pictures': { type: 'folder', children: {} },
                                    'README.txt': { type: 'file' },
                                }
                            }
                        }
                    },
                    'usr': { type: 'folder', children: {} },
                    'var': { type: 'folder', children: {} },
                }
            }
        };

        let currentPath = '/';
        let notepadTabs = [];
        let activeTab = null;

        function init() {
            initFilesApp();
            initNotepadApp();
            setupWindowDragging();
        }

        function initFilesApp() {
            const openFilesBtn = document.getElementById('open-files');
            const filesWindow = document.getElementById('files-window');
            const filesUp = document.getElementById('files-up');

            openFilesBtn.addEventListener('click', () => {
                filesWindow.classList.remove('hidden');
                bringToFront(filesWindow);
                renderFilesApp();
            });

            filesWindow.querySelector('.win-close').addEventListener('click', () => {
                filesWindow.classList.add('hidden');
            });

            filesUp.addEventListener('click', navigateUp);
            renderFilesApp();
        }

        function renderFilesApp() {
            const pathEl = document.getElementById('files-path');
            const listEl = document.getElementById('files-list');
            const filesUp = document.getElementById('files-up');

            pathEl.textContent = currentPath;
            listEl.innerHTML = '';

            const node = getNodeAtPath(currentPath);
            if (!node || node.type !== 'folder') return;

            const entries = Object.entries(node.children);
            entries.sort((a, b) => {
                if (a[1].type !== b[1].type) return a[1].type === 'folder' ? -1 : 1;
                return a[0].localeCompare(b[0]);
            });

            entries.forEach(([name, entry]) => {
                const item = document.createElement('div');
                item.className = `fs-item ${entry.type}`;
                item.textContent = name;

                if (entry.type === 'folder') {
                    item.addEventListener('dblclick', () => {
                        currentPath = (currentPath === '/' ? '' : currentPath) + '/' + name;
                        renderFilesApp();
                    });
                }

                listEl.appendChild(item);
            });

            filesUp.disabled = currentPath === '/';
        }

        function navigateUp() {
            if (currentPath === '/') return;
            currentPath = currentPath.split('/').slice(0, -1).join('/') || '/';
            renderFilesApp();
        }

        function getNodeAtPath(path) {
            if (path === '/') return filesystem['/'];
            const parts = path.split('/').filter(Boolean);
            let node = filesystem['/'];
            for (const part of parts) {
                if (node.type !== 'folder' || !node.children[part]) return null;
                node = node.children[part];
            }
            return node;
        }

        function initNotepadApp() {
            const openNotepadBtn = document.getElementById('open-notepad');
            const notepadWindow = document.getElementById('notepad-window');
            const newTabBtn = document.getElementById('new-tab');
            const editor = document.getElementById('editor');

            loadNotepadFromStorage();

            openNotepadBtn.addEventListener('click', () => {
                notepadWindow.classList.remove('hidden');
                bringToFront(notepadWindow);
                if (notepadTabs.length === 0) {
                    createNewTab();
                } else {
                    renderTabs();
                    if (activeTab !== null && notepadTabs[activeTab]) {
                        editor.value = notepadTabs[activeTab].content;
                    }
                }
            });

            notepadWindow.querySelector('.win-close').addEventListener('click', () => {
                saveNotepadToStorage();
                notepadWindow.classList.add('hidden');
            });

            newTabBtn.addEventListener('click', createNewTab);

            editor.addEventListener('input', () => {
                if (activeTab !== null && notepadTabs[activeTab]) {
                    notepadTabs[activeTab].content = editor.value;
                    saveNotepadToStorage();
                }
            });

            if (notepadTabs.length === 0) {
                createNewTab();
            }
        }

        function createNewTab() {
            const newTab = {
                id: Date.now(),
                name: `Tab ${notepadTabs.length + 1}`,
                content: ''
            };
            notepadTabs.push(newTab);
            activeTab = notepadTabs.length - 1;
            renderTabs();
            document.getElementById('editor').value = '';
            saveNotepadToStorage();
        }

        function renderTabs() {
            const tabsContainer = document.getElementById('tabs');
            const editor = document.getElementById('editor');
            tabsContainer.innerHTML = '';

            notepadTabs.forEach((tab, index) => {
                const tabEl = document.createElement('div');
                tabEl.className = 'tab';
                if (index === activeTab) tabEl.classList.add('active');

                const name = document.createElement('span');
                name.textContent = tab.name;
                tabEl.appendChild(name);

                const closeBtn = document.createElement('button');
                closeBtn.className = 'tab-close';
                closeBtn.textContent = '×';
                closeBtn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    notepadTabs.splice(index, 1);
                    if (activeTab >= notepadTabs.length) {
                        activeTab = Math.max(0, notepadTabs.length - 1);
                    }
                    if (notepadTabs.length === 0) {
                        createNewTab();
                    } else {
                        renderTabs();
                        if (activeTab !== null) {
                            editor.value = notepadTabs[activeTab].content;
                        }
                    }
                    saveNotepadToStorage();
                });
                tabEl.appendChild(closeBtn);

                tabEl.addEventListener('click', (e) => {
                    if (!e.target.classList.contains('tab-close')) {
                        activeTab = index;
                        renderTabs();
                        editor.value = tab.content;
                    }
                });

                tabsContainer.appendChild(tabEl);
            });
        }

        function saveNotepadToStorage() {
            localStorage.setItem('notepad-tabs', JSON.stringify(notepadTabs));
            localStorage.setItem('notepad-active', activeTab);
        }

        function loadNotepadFromStorage() {
            const saved = localStorage.getItem('notepad-tabs');
            const savedActive = localStorage.getItem('notepad-active');
            if (saved) {
                notepadTabs = JSON.parse(saved);
                activeTab = savedActive ? parseInt(savedActive) : 0;
            }
        }

        function bringToFront(el) {
            const windows = document.querySelectorAll('.window');
            let maxZ = 10;
            windows.forEach(w => {
                const z = parseInt(window.getComputedStyle(w).zIndex) || 10;
                if (z > maxZ) maxZ = z;
            });
            el.style.zIndex = maxZ + 1;
        }

        function setupWindowDragging() {
            document.querySelectorAll('.window').forEach(w => {
                let isDragging = false;
                let offsetX = 0;
                let offsetY = 0;

                const header = w.querySelector('.window-header');
                header.addEventListener('mousedown', (e) => {
                    isDragging = true;
                    offsetX = e.clientX - w.offsetLeft;
                    offsetY = e.clientY - w.offsetTop;
                    bringToFront(w);
                });

                document.addEventListener('mousemove', (e) => {
                    if (isDragging) {
                        w.style.left = Math.max(0, e.clientX - offsetX) + 'px';
                        w.style.top = Math.max(50, e.clientY - offsetY) + 'px';
                    }
                });

                document.addEventListener('mouseup', () => {
                    isDragging = false;
                });
            });
        }

        init();
    </script>
</body>
</html>
